    /// Timestamp of last phylactery update
    pub last_updated: DateTime<Utc>,
}

#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct IdentityCommit {
    pub timestamp: DateTime<Utc>,
    pub authority: String,
    pub change: String,
    pub signature: Option<String>,
}

impl Default for Phylactery {
    fn default() -> Self {
        Self {
            identity_vector: String::new(),
            commit_chain: Vec::new(),
            current_anchor: None,
            last_updated: Utc::now(),
        }
    }
}

/// E_t: Economy — Neuro-credit state
