#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct TaskStateObject {
    pub task_id: String,
    pub objective: String,
    pub constraints: Vec<String>,
    pub success_criteria: Vec<String>,
    pub declared_unknowns: Vec<String>,
    pub urgency: String, // low, normal, high, critical
    pub intent_priority_score: f64,
    pub goal_valence_vector: GoalValence,
    pub authority_shrink_level: f64,
    pub canon_anchor_weight: f64,
    pub predicted_failure_modes: Vec<String>,
    pub phase_state: String, // anchor, skeleton, ground, flesh, verify, repair/refuse
}

#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct GoalValence {
    pub truth: f64,
    pub speed: f64,
    pub safety: f64,
    pub continuity: f64,
    pub operator_preference: f64,
}

impl Default for TaskStateObject {
    fn default() -> Self {
        Self {
            task_id: String::new(),
            objective: String::new(),
            constraints: Vec::new(),
            success_criteria: Vec::new(),
            declared_unknowns: Vec::new(),
            urgency: "normal".to_string(),
            intent_priority_score: 0.5,
            goal_valence_vector: GoalValence::default(),
            authority_shrink_level: 1.0,
            canon_anchor_weight: 0.5,
            predicted_failure_modes: Vec::new(),
            phase_state: "anchor".to_string(),
        }
    }
}

impl Default for GoalValence {
    fn default() -> Self {
        Self {
            truth: 1.0,
            speed: 0.4,
            safety: 0.9,
            continuity: 0.8,
            operator_preference: 0.7,
        }
    }
}

/// B_t: Bridge — Measurement and gating state
///
/// Owned by orchestration layer. Tracks the status of all four gates
/// and measurement signals needed to pass control through the system.
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct BridgeState {
    /// Macro continuity gate: identity coherence across sessions
    pub kappa_macro: Option<f64>,
    pub theta_kappa_macro: f64,

    /// Verifier gate: proof/claim acceptance threshold
    pub verification_score: Option<f64>,
