    /// Consent gate: governance risk threshold
    pub risk_score: Option<f64>,
    pub tau_consent: f64,

    /// Measurement timestamp
    pub measured_at: DateTime<Utc>,

    /// Gate clearance statuses
    pub gates_cleared: HashMap<String, bool>,
}

impl Default for BridgeState {
    fn default() -> Self {
        Self {
            kappa_macro: None,
            theta_kappa_macro: 0.7,
            verification_score: None,
            tau_verify: 0.5,
            risk_score: None,
            tau_consent: 0.3,
            measured_at: Utc::now(),
            gates_cleared: HashMap::new(),
        }
    }
}

/// S_t: Semantic State — Memory retrieval path state
