    pub entries: HashMap<String, (String, DateTime<Utc>, f64)>,

    /// Total number of retrieval events recorded in this graph
    pub total_retrievals: u64,
}

impl Default for MemoryGraph {
    fn default() -> Self {
        Self {
            edges: HashMap::new(),
            entries: HashMap::new(),
            total_retrievals: 0,
        }
    }
