/// Bridge Layer — Python/Rust Cognitive Engine Integration
///
/// This module defines the protocol and client for communicating with the
/// Python reference implementations of AEON, ADCCL, and MYELIN. The bridge
/// allows the Rust gateway to orchestrate requests through the full four-layer
/// architecture while keeping the cognitive engines running in Python.
///
/// Architecture:
/// - Rust gateway maintains request lifecycle and unified state vector
/// - Python sidecar process runs the cognitive engines (AEON, ADCCL, MYELIN)
/// - Bridge communicates via HTTP + JSON (initial), upgradeable to gRPC
/// - All state transitions go through the bridge

use serde::{Deserialize, Serialize};
use crate::state_vector::UnifiedStateVector;
use std::sync::Arc;

/// PythonBridgeClient — HTTP client to the Python cognitive engine sidecar
pub struct PythonBridgeClient {
    base_url: String,
    http_client: reqwest::Client,
}

impl PythonBridgeClient {
    pub fn new(base_url: &str) -> Self {
        Self {
            base_url: base_url.to_string(),
            http_client: reqwest::Client::new(),
        }
    }

    /// Call AEON.initialize to bootstrap the task state from a user prompt
    ///
    /// Input: raw prompt + goal valence preferences
    /// Output: initialized TaskStateObject with anchor, skeleton, grounding
    pub async fn aeon_initialize(
        &self,
        prompt: &str,
        valence: serde_json::Value,
    ) -> Result<serde_json::Value, Box<dyn std::error::Error>> {
        let request = serde_json::json!({
            "prompt": prompt,
            "valence": valence,
        });

        let response = self.http_client
            .post(&format!("{}/aeon/initialize", self.base_url))
            .json(&request)
            .send()
            .await?;

        Ok(response.json().await?)
    }

    /// Call MYELIN.retrieve to search memory for relevant prior context
    ///
    /// Input: current task, query terms
    /// Output: ranked list of memory entries + hardening updates
    pub async fn myelin_retrieve(
        &self,
        task_id: &str,
        query: &str,
    ) -> Result<serde_json::Value, Box<dyn std::error::Error>> {
        let request = serde_json::json!({
            "task_id": task_id,
            "query": query,
        });

        let response = self.http_client
            .post(&format!("{}/myelin/retrieve", self.base_url))
            .json(&request)
            .send()
            .await?;

        Ok(response.json().await?)
    }

    /// Call ADCCL.plan to generate anti-drift verified reasoning steps
    ///
    /// Input: task state + retrieved memory + LLM capabilities
    /// Output: sequence of reasoning steps with drift annotations
    pub async fn adccl_plan(
        &self,
        state: &UnifiedStateVector,
        retrieved_context: &str,
    ) -> Result<serde_json::Value, Box<dyn std::error::Error>> {
        let request = serde_json::json!({
            "state": serde_json::to_value(state)?,
            "retrieved_context": retrieved_context,
        });

        let response = self.http_client
            .post(&format!("{}/adccl/plan", self.base_url))
            .json(&request)
            .send()
            .await?;

        Ok(response.json().await?)
    }

    /// Call ADCCL.verify to check if a generated response is safe to commit
    ///
    /// Input: proposed output + reasoning trace + verification criteria
    /// Output: verification score + recommended actions (accept/revise/refuse)
    pub async fn adccl_verify(
        &self,
        proposed_output: &str,
        reasoning_trace: &str,
        state: &UnifiedStateVector,
    ) -> Result<serde_json::Value, Box<dyn std::error::Error>> {
        let request = serde_json::json!({
            "proposed_output": proposed_output,
            "reasoning_trace": reasoning_trace,
            "state": serde_json::to_value(state)?,
        });

        let response = self.http_client
            .post(&format!("{}/adccl/verify", self.base_url))
            .json(&request)
            .send()
            .await?;

        Ok(response.json().await?)
    }

    /// Call MYELIN.harden to record successful retrieval paths
    ///
    /// Input: memory paths used in this session + outcomes
    /// Output: updated path-dependent weights
    pub async fn myelin_harden(
        &self,
        paths_used: Vec<String>,
        outcome: &str,
    ) -> Result<serde_json::Value, Box<dyn std::error::Error>> {
        let request = serde_json::json!({
            "paths_used": paths_used,
            "outcome": outcome,
        });

        let response = self.http_client
            .post(&format!("{}/myelin/harden", self.base_url))
            .json(&request)
            .send()
            .await?;

        Ok(response.json().await?)
    }

    /// Health check — ping the Python bridge
    pub async fn health(&self) -> Result<bool, Box<dyn std::error::Error>> {
        let response = self.http_client
            .get(&format!("{}/health", self.base_url))
            .send()
            .await?;

        Ok(response.status().is_success())
    }
}

/// Bridge Request Envelope — wraps the unified state for transmission
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct BridgeRequest {
    pub state: UnifiedStateVector,
