        self.state.check_admissibility()
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_request_lifecycle_initialization() {
        let state = UnifiedStateVector::new();
        let bridge = Arc::new(PythonBridgeClient::new("http://localhost:9000"));
        let lifecycle = RequestLifecycle::new(state, bridge);

        assert_eq!(lifecycle.stage, RequestStage::AegisPolicy);
    }

    #[tokio::test]
    async fn test_request_lifecycle_advancement() {
        let state = UnifiedStateVector::new();
        let bridge = Arc::new(PythonBridgeClient::new("http://localhost:9000"));
        let mut lifecycle = RequestLifecycle::new(state, bridge);

