    pub state: UnifiedStateVector,
    pub operation: String,
    pub result: serde_json::Value,
    pub success: bool,
    pub error: Option<String>,
}

/// Request Lifecycle — the 8 stages that each request flows through
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum RequestStage {
    // Gate 1: AEGIS (governance)
    AegisPolicy,

    // Stage 2: AEON (task initialization)
    AeonInitialize,

    // Stage 3: MYELIN (memory retrieval)
    MyelinRetrieve,

    // Stage 4: ADCCL (anti-drift planning)
    AdcclPlan,

    // Stage 5: LLM generation
    LlmGenerate,

    // Stage 6: ADCCL (anti-drift verification)
    AdcclVerify,

    // Stage 7: MYELIN (path hardening)
    MyelinHarden,

    // Gate 8: AEGIS (final audit)
    AegisAudit,
}

/// Request Lifecycle Manager — orchestrates the 8-stage flow
pub struct RequestLifecycle {
    pub stage: RequestStage,
    pub state: UnifiedStateVector,
    pub bridge: Arc<PythonBridgeClient>,
}

impl RequestLifecycle {
    pub fn new(state: UnifiedStateVector, bridge: Arc<PythonBridgeClient>) -> Self {
        Self {
            stage: RequestStage::AegisPolicy,
            state,
            bridge,
        }
    }

    /// Advance to the next stage, performing the appropriate action
    pub async fn advance(&mut self) -> Result<(), Box<dyn std::error::Error>> {
        match self.stage {
            RequestStage::AegisPolicy => {
                // Check governance constraints (law.json)
                // TODO: wire to AEGIS policy check
                self.stage = RequestStage::AeonInitialize;
            }
            RequestStage::AeonInitialize => {
                // Initialize task state from the request
                // TODO: call bridge.aeon_initialize()
                self.stage = RequestStage::MyelinRetrieve;
            }
            RequestStage::MyelinRetrieve => {
                // Retrieve relevant memory
                // TODO: call bridge.myelin_retrieve()
                self.stage = RequestStage::AdcclPlan;
            }
            RequestStage::AdcclPlan => {
                // Generate anti-drift reasoning plan
                // TODO: call bridge.adccl_plan()
                self.stage = RequestStage::LlmGenerate;
            }
            RequestStage::LlmGenerate => {
                // Call the LLM provider with the plan
                // TODO: route through failover router
                self.stage = RequestStage::AdcclVerify;
            }
            RequestStage::AdcclVerify => {
                // Verify the output against drift and verification gates
                // TODO: call bridge.adccl_verify()
                self.stage = RequestStage::MyelinHarden;
            }
            RequestStage::MyelinHarden => {
                // Harden the memory paths that were used
                // TODO: call bridge.myelin_harden()
                self.stage = RequestStage::AegisAudit;
            }
            RequestStage::AegisAudit => {
                // Final governance audit before returning
                // TODO: wire to AEGIS audit gate
            }
        }
        Ok(())
    }

    /// Check if all gates are cleared for the current state
    pub fn gates_cleared(&self) -> bool {
        self.state.check_admissibility()
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_request_lifecycle_initialization() {
        let state = UnifiedStateVector::new();
        let bridge = Arc::new(PythonBridgeClient::new("http://localhost:9000"));
        let lifecycle = RequestLifecycle::new(state, bridge);

        assert_eq!(lifecycle.stage, RequestStage::AegisPolicy);
    }

    #[tokio::test]
    async fn test_request_lifecycle_advancement() {
        let state = UnifiedStateVector::new();
        let bridge = Arc::new(PythonBridgeClient::new("http://localhost:9000"));
        let mut lifecycle = RequestLifecycle::new(state, bridge);

        assert_eq!(lifecycle.stage, RequestStage::AegisPolicy);

        lifecycle.advance().await.unwrap();
        assert_eq!(lifecycle.stage, RequestStage::AeonInitialize);

        lifecycle.advance().await.unwrap();
        assert_eq!(lifecycle.stage, RequestStage::MyelinRetrieve);
    }
}
